// Webhook input is in $('Webhook (email.received)').first().json.body (or root if no body wrapper)
// Vault response gives us the signing key for later HMAC signing

const webhookData = $('Webhook (email.received)').first().json;
const eventBody = webhookData.body || webhookData;
const event_id = eventBody.id;
const trace_id = eventBody.trace_id;
const payload = typeof eventBody.payload === 'string' ? JSON.parse(eventBody.payload) : eventBody.payload;

if (!event_id) throw new Error('missing event id');
if (!trace_id) throw new Error('missing trace_id');
if (!payload || !payload.gmail_message_id) {
  throw new Error('missing gmail_message_id in payload');
}

const vaultData = $input.first().json;
const signing_key = vaultData?.data?.data?.payload_hmac_key;
if (!signing_key) {
  throw new Error('signing key not returned by vault — check vault-token-header credential scope');
}

return [{
  json: {
    event_id,
    trace_id,
    gmail_message_id: payload.gmail_message_id,
    received_at: payload.received_at || null,
    signing_key
  }
}];

