const e = $input.first().json;
const extracted = $('Extract Event Fields').first().json;
if (!e.body_text_safe) {
  throw new Error('emails.body_text_safe is empty — sanitisation step missed?');
}

const system = `You are an email classification system for Jo, a business owner.
Jo runs: The Olde Malthouse pub (Tintagel, Cornwall), a property company (7 properties),
and manages personal and family matters.

Classify into exactly one category:
  invoice | action-required | report-attachment | school-medical | property | pub | fyi | junk

Determine entity_id: 1=Trading (pub), 2=Estates (property), 3=Personal, 4=Family

Return ONLY valid JSON. No markdown. No explanation.
Format: {"category": "...", "entity_id": N, "confidence_score": 0.0-1.0}`;

const user = `From: ${e.from_address || '(unknown)'}\nSubject: ${e.subject || '(no subject)'}\nBody: ${(e.body_text_safe || '').slice(0, 4000)}`;

const prompt = `${system}\n\n${user}\n\nResult:`;

return [{
  json: {
    ...e,
    prompt,
    trace_id: extracted.trace_id,
    event_id: extracted.event_id,
    signing_key: extracted.signing_key
  }
}];

// llm-router returns {text, model_used, tier, escalated, ...}.
// `text` should be a JSON string per the prompt contract.

const route = $input.first().json;
const email = $('Build Classification Prompt').first().json;

const VALID_CATEGORIES = ['invoice','action-required','report-attachment','school-medical','property','pub','fyi','junk'];
const VALID_ENTITIES = [1,2,3,4];

let parsed;
try {
  let raw = (route.text || '').trim();
  if (raw.startsWith('```')) {
    raw = raw.replace(/^```[a-z]*\n?/, '').replace(/```\s*$/, '').trim();
  }
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error(`classifier returned non-JSON: ${(route.text || '').slice(0, 200)}`);
}

if (!VALID_CATEGORIES.includes(parsed.category)) {
  throw new Error(`invalid category: ${parsed.category}`);
}
if (!VALID_ENTITIES.includes(parsed.entity_id)) {
  throw new Error(`invalid entity_id: ${parsed.entity_id}`);
}
if (typeof parsed.confidence_score !== 'number' || parsed.confidence_score < 0 || parsed.confidence_score > 1) {
  throw new Error(`invalid confidence_score: ${parsed.confidence_score}`);
}

const crypto = require('crypto');

return [{
  json: {
    ...email,
    classification: parsed.category,
    classified_entity_id: parsed.entity_id,
    confidence_score: parsed.confidence_score,
    model_used: route.model_used,
    tier: route.tier,
    escalated: route.escalated,
    escalation_reason: route.escalation_reason || null,
    ai_raw_output: route.text,
    ai_input_hash: crypto.createHash('sha256').update(email.prompt).digest('hex')
  }
}];

// HMAC-sign the email.classified event payload using the signing key
// fetched from Vault earlier in the pipeline (NOT $env — that's blocked).

const crypto = require('crypto');
const v = $('Validate Classification').first().json;
const emailRow = $('Update Email Row').first().json;
const extracted = $('Extract Event Fields').first().json;

const payload = {
  email_id: emailRow.id,
  gmail_message_id: v.gmail_message_id,
  classification: v.classification,
  entity_id: v.classified_entity_id,
  confidence_score: v.confidence_score,
  model_used: v.model_used,
  tier: v.tier,
  escalated: v.escalated
};

const canonical = JSON.stringify(payload, Object.keys(payload).sort());
const signature = crypto.createHmac('sha256', extracted.signing_key)
                        .update(canonical)
                        .digest('hex');

return [{
  json: {
    event_type: 'email.classified',
    source: 'email_pipeline',
    classified_entity_id: v.classified_entity_id,
    payload_json: JSON.stringify(payload),
    payload_signature: signature,
    trace_id: extracted.trace_id,
    parent_event_id: extracted.event_id,
    idempotency_key: 'email_classified_' + v.gmail_message_id,
    pipeline_version: '1.0',
    email_id: emailRow.id,
    ai_input_hash: v.ai_input_hash,
    ai_raw_output: (v.ai_raw_output || '').replace(/'/g, "''"),
    model_used: v.model_used,
    classification: v.classification,
    confidence_score: v.confidence_score
  }
}];
